import json, os, sys, urllib.request, urllib.error, re, ssl

ctx = ssl.create_default_context()
ctx.load_verify_locations("/usr/local/lib/python3.14/site-packages/certifi/cacert.pem")

ISSUES_PATH = os.path.join(os.path.dirname(__file__), "issues.json")

def og_image(url):
    try:
        req = urllib.request.Request(url, headers={"User-Agent": "Mozilla/5.0"})
        with urllib.request.urlopen(req, timeout=10, context=ctx) as r:
            html = r.read(50000).decode("utf-8", errors="ignore")
        m = re.search(r'<meta[^>]+property=["\']og:image["\'][^>]+content=["\']([^"\']+)', html)
        if not m:
            m = re.search(r'content=["\']([^"\']+)["\'][^>]+property=["\']og:image', html)
        return m.group(1) if m else ""
    except:
        return ""

